// displayFrom returns the display name if non-empty, otherwise the email address.
func displayFrom(name, email string) string {
	if name != "" {
		return name
	}
	return email
}

// truncateStr truncates s to at most maxLen characters, appending "…" if truncated.
func truncateStr(s string, maxLen int) string {
	runes := []rune(s)
	if len(runes) <= maxLen {
		return s
	}
	return string(runes[:maxLen-1]) + "…"
}

// messageSortFieldStr returns the URL parameter string for the given sort field.
func messageSortFieldStr(f query.MessageSortField) string {
	switch f {
	case query.MessageSortBySize:
		return "size"
	case query.MessageSortBySubject:
		return "subject"
	default:
		return "date"
	}
}

// sortDirStr returns "asc" or "desc" for the given sort direction.
func sortDirStr(d query.SortDirection) string {
	if d == query.SortAsc {
		return "asc"
	}
	return "desc"
}

